export function addServerTemplate (template: NuxtServerTemplate): NuxtServerTemplate {
  const nuxt = useNuxt()

  nuxt.options.nitro.virtual ||= {}
  nuxt.options.nitro.virtual[template.filename] = template.getContents

  return template
}

export async function getUserSession(event: UseSessionEvent): Promise<UserSession> {
  const session = await _useSession(event)
  return {
    ...session.data,
    id: session.id!,
  }
}

if (options.webAuthn) {
  composables.push({ name: 'useWebAuthn', from: resolver.resolve('./runtime/app/composables/webauthn') })
}

const props = withDefaults(defineProps<SidebarProps>(), {
  side: 'left',
  variant: 'sidebar',
  collapsible: 'offcanvas',
})

const {
    registerEndpoint = '/api/webauthn/register',
    authenticateEndpoint = '/api/webauthn/authenticate',
    useBrowserAutofill = false,
  } = options

const assertionResponse = await startAuthentication({
  optionsJSON: requestOptions,
  useBrowserAutofill,
})

if (Object.keys(session).length > 0) {
  await sessionHooks.callHookParallel('fetch', session, event)
}

for (const provider of atprotoProviders) {
  const config = runtimeConfig.oauth[provider] as AtprotoProviderClientMetadata

  if (getClientMetadataFilename(provider, config) === path) {
    return getAtprotoClientMetadata(event, provider)
  }
}

for (const [id, value] of allItems.value) {
  const score = contains(value, filterState.search)
  filterState.filtered.items.set(id, score ? 1 : 0)
  if (score)
    itemCount++
}

if (!isInNuxt) {
    nuxt.options.css.unshift(file)
  }

  nuxt.options.alias['#tailwindcss'] = file
  nuxt.options.alias['#tailwindcss/sources'] = sourcesTemplate.dst

if (!nuxt.options.nitro.unenv.external.includes('node:crypto')) {
// @ts-expect-error see comment above
  nuxt.options.nitro.unenv.external.push('node:crypto')
}

const composables = [
  { name: 'useUserSession', from: resolver.resolve('./runtime/app/composables/session') },
]

for (const provider of atprotoProviders) {
  runtimeConfig.oauth[provider] = defu(runtimeConfig.oauth[provider], atprotoProviderDefaultClientMetadata)
}

try {
  await nitroApp.hooks.callHook('evlog:enrich', enrichCtx)
} catch (err) {
  console.error('[evlog] enrich failed:', err)
}

const { payload } = await jose.jwtVerify(token, JWKS, {
  audience: options.audience,
  issuer: options.issuer,
})

const resetConditionState = () => {
  isDisabled.value = false
  isHidden.value = false
  isRequired.value = false
  overrideOptions.value = undefined
}

if (autoRefresh.value) {
  fetchLogs()
  autoRefreshInterval = setInterval(fetchLogs, 2000)
} else if (autoRefreshInterval) {
  clearInterval(autoRefreshInterval)
  autoRefreshInterval = null
}

if (props.fluid) {
  handleFluidMove(size, position)
}
else {
  activeItem.size = size
  activeItem.position = position
}

export const { register, onRequestError } = createInstrumentation({
  service: 'next-playground',
  drain: createFsDrain(),
  captureOutput: true,
})

const updateAppSettings = (settings: AppSettings) => {
  cookieAppSettings.value = customDefu(settings, cookieAppSettings.value)
}

switch (s) {
  case 'idle': return 'text-dimmed'
  case 'inflight': return 'text-primary'
  case 'delivered': return 'text-emerald-500'
}

const runtimeConfig = shouldProbeRuntimeConfig(fields, overrides)
    ? await getRuntimeConfig()
    : undefined
